#!/usr/bin/env bash
# pre-commit-version-check.sh — Block commits when marketplace.json is out of
# sync with the per-plugin plugin.json files it is derived from.
#
# marketplace.json's plugins[] array is regenerated by scripts/regen_marketplace.py.
# Editing marketplace.json by hand and committing is not the workflow; bump the
# version (or description, etc.) in plugins/<name>/.claude-plugin/plugin.json
# and re-run the regenerator. Subsumes the old version-only check: a version
# mismatch is just one kind of drift the regenerator surfaces.
#
# Install: ln -sf ../../scripts/pre-commit-version-check.sh .git/hooks/pre-commit

set -euo pipefail

# Resolve via git (works whether the hook is installed as a symlink, a copy, or
# wired via core.hooksPath). Falling back to $0-relative resolution would give
# the wrong directory when the hook is a symlink at .git/hooks/pre-commit.
REPO_ROOT="$(git rev-parse --show-toplevel)"

if ! uv run python "$REPO_ROOT/scripts/regen_marketplace.py" --check; then
    echo ""
    echo "Bump versions / descriptions in plugins/<name>/.claude-plugin/plugin.json,"
    echo "run \`python scripts/regen_marketplace.py\`, stage the result, and commit."
    exit 1
fi
